VALUES
  ('cpa-moex-01101', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得基本稅額條例規定，出售下列何種金融投資商品之所得，可能計入個人基本所得額？', '["國內公司發行之公開募集基金", "國內未上市公司發行之公司債", "國外公司發行之連動式債券", "依我國金融資產證券化規定發行之受益憑證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01102', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及其相關法規規定，多層次傳銷事業的個人參加人，因為下層直銷商向傳銷事業進貨或購進 商品累積積分額（或金額）達一定標準，而自該事業取得的業績獎金，應申報為何類所得？', '["營利所得", "薪資所得", "執行業務所得", "其他所得"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01103', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，委託人為營利事業之信託契約，明定信託利益全部屬於委託人，於信託關係存續中， 變更為非委託人者，應如何課稅？', '["由變更後受益人將其享有信託利益之權利價值，併入變更年度之所得額，依法課徵所得稅", "由變更後受益人將其享有信託利益之權利價值，併入信託契約成立年度之所得額，依法課徵所得稅", "將變更後受益人享有信託利益之權利價值，併入委託人變更年度之贈與，依法課徵贈與稅", "由受託人按該受益人享有信託利益之權利價值，採就源扣繳的方式扣繳稅款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01104', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '當年度1月無連續三日國定假日者，依所得稅法第88條各類所得稅款之扣繳義務人，應於何時將上一年 內扣繳各納稅義務人之稅款數額，開具扣繳憑單，彙報該管稽徵機關查核？', '["每年1月底前", "每年2月底前", "每年3月底前", "每年4月底前"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01105', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，我國105年度綜合所得稅課稅級距及稅率，下列敘述何者正確？', '["分為6級，最高為40％", "分為6級，最低為6％", "分為5級，最低為6％", "分為6級，最高為45％"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01106', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '假設甲商號民國105年1、2月有銷項稅額35萬元，進項稅額35萬元，甲商號遲至105年4月20日才 申報加值型及非加值型營業稅，甲商號將被處以怠報金為新臺幣多少元？', '["0元", "1,000元", "3,000元", "30,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01107', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，保險業經營專屬本業、非專屬本業及再保費等收入之營業稅稅率分 別為若干？', '["5%；5%；2%", "2%；5%；1%", "5%；5%；1%", "5%；2%；1%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01108', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲公司委託乙公司管理處分信託財產，雙方訂定他益信託契約，下列何者應課徵營業稅？', '["委託人甲公司將信託財產登記為受託人乙公司名義", "委託人甲公司變更信託契約之受託人為丙公司，受託人乙公司將信託財產登記為丙公司名義", "受託人乙公司於信託關係消滅時，將委託人甲公司的信託財產返還予甲公司", "受託人乙公司於信託關係結束後，依信託契約將委託財產移轉與受益人丁公司"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01109', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列敘述何者不符合營業稅法規定？', '["營業人短漏開統一發票經查獲者，除補稅外，按所漏稅額處10倍以下罰鍰", "營業人一年內經查獲短漏開統一發票達3次者，主管稽徵機關應停止其營業", "營業人短漏報銷售額經查獲者，除補稅外，按所漏稅額處5倍以下罰鍰", "營業人未依規定期限申報銷售額，應加徵之滯報金，其金額不得少於新臺幣1,200元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01110', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '假設甲公司進口洋菸完稅價格為500,000元，關稅69,000元，菸酒稅5,900元，菸品健康福利捐為5,000元， 依營業稅法規定，甲公司應繳納多少元的進口營業稅？', '["25,000元", "28,450元", "28,745元", "28,995元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01111', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法及其相關法規規定，地價稅每年徵收一次者，納稅義務基準日為何日？', '["8月31日", "9月15日", "9月22日", "12月31日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01112', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某甲取得土地時，核定移轉現值40萬元；某甲於98年死亡時，其子繼承該土地，當期土地公告現值90萬 元。今年初其子將土地移轉第三人，申報移轉現值200萬元。假設不考慮物價變動之調整，則本次移轉， 依土地稅法規定，應納土地增值稅為多少元？', '["23萬元", "24萬元", "32萬元", "52萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01113', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '假設某甲本年度在某縣有一般用地二筆，A地4公畝，每公畝公告現值為500萬元，公告地價為300萬 元，申報地價為250萬元；B地5公畝，每公畝公告現值為200萬元，公告地價為125萬元，申報地價為 80萬元，若該縣地價稅累進起點地價為100萬元，依土地稅法規定，某甲本年度應納地價稅額若干元？', '["24萬元", "25萬5千元", "31萬5千元", "35萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01114', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法第3條之1規定，下列有關信託土地課徵地價稅，其稅基計算與納稅義務人之敘述，何者正 確？', '["與委託人在同一縣市所有之土地合併計算地價總額，並以委託人為納稅義務人", "與委託人在同一縣市所有之土地合併計算地價總額，並以受託人為納稅義務人", "與受託人在同一縣市所有之土地合併計算地價總額，並以委託人為納稅義務人", "與受託人在同一縣市所有之土地合併計算地價總額，並以受託人為納稅義務人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01115', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，計算地價稅累進起點地價時，包括下列何種土地？', '["工業用地", "自用住宅用地", "礦業用地", "農業用地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01116', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，有關遺產稅及贈與稅申報之敘述，下列何者正確？', '["被繼承人死亡遺有財產者，納稅義務人應於被繼承人死亡之日起 6 個月內，向就近的國稅局稽徵所依 規定辦理遺產稅申報", "贈與人在一年內贈與他人之財產總值超過贈與稅免稅額時，應於超過免稅額之贈與行為發生後 30 日 內，依規定辦理贈與稅申報。具有正當理由不能如期申報者，應於30日限期屆滿前，以書面申請延長 之。申請延長期限以2個月為限", "被繼承人為經常居住中華民國境外之中華民國國民或非中華民國國民死亡時，在中華民國境內遺有財 產者，應向在臺住所所在縣市之主管稽徵機關辦理遺產稅申報", "同一贈與人在同一年內有兩次以上依規定應申報納稅之贈與行為者，應於辦理後一次贈與稅申報時， 將同一年內以前各次之贈與事實及納稅情形合併申報"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01117', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某甲將5,000萬元存款信託與某銀行，期間20年，約定受託人每年支付100萬元予其子，期滿時剩餘信 託財產歸屬某甲。信託開始時，郵局一年期定期儲金利率為2%，則依遺產及贈與稅法規定計算之贈與總 額為多少元？（提示：2%，20年，1元之複利現值為0.673、年金現值為16.351）', '["5,000萬元", "3,364萬9千元", "2,000萬元", "1,635萬1千元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01118', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，下列有關我國遺產稅之敘述何者正確？', '["經常居住在境外之我國國民死亡，應就其在我國境內及境外之財產，課徵遺產稅", "非我國國民在我國境內死亡，應就其在我國境內及境外之財產，課徵遺產稅", "被繼承人死亡前3年內，在我國境內有住所者，即屬經常居住我國境內", "無遺囑執行人時，遺產稅之納稅義務人為繼承人或受遺贈人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01119', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法之規定，遺產稅之免稅額，每遇消費者物價指數較上次調整之指數累計上漲達多少以 上時，自次年起按上漲程度調整之？', '["3%", "7%", "10%", "20%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01120', 'cpa', 'cpa-moex-105-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，除本法第20條所規定之贈與外，贈與人在一年內贈與他人之財產總值超過贈與 稅免稅額時，應於超過免稅額之贈與行為發生後幾日內，向主管稽徵機關依本法規定辦理贈與稅申報？', '["15日", "20日", "30日", "60日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "a0fa3fd88c6d", "answer_pdf_sha1": "2f8a55112784", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01121', 'cpa', 'cpa-moex-105-1cd83735', 'sub-cpa-06', NULL, 'essay', '臺北公司於 X1年 1月 1日取得臺中公司 80%股權，採權益法處理該項投資，
